{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires distinguishing between the absolute energy of the exciton state relative to the band edge and the binding energy magnitude to correctly apply the Rydberg formula.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Calculate the exciton binding energy (E_b) for the n=1 state. Determine the binding energy magnitude by finding the difference between the band gap energy and the energy of the 1s exciton peak. Explicitly define whether the binding energy is being treated as a positive magnitude or a negative energy level relative to the conduction band minimum."
    },
    {
      "label": "helper_2",
      "instructions": "Using the binding energy magnitude from the first step, apply the Rydberg scaling law for exciton states, where the energy of the n-th state is given by E_n = E_b / n^2. Calculate the specific value for n=3 and ensure the final result reflects the correct sign convention requested by the problem (the energy level relative to the band edge)."
    }
  ],
  "synthesis_brief": "Combine the binding energy magnitude from helper 1 with the n=3 scaling factor from helper 2 to provide the final energy level, ensuring the sign correctly represents the energy relative to the band gap threshold."
}

